namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple and delicious pizza with fresh mozzarella and basil.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute over sauce.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
            AverageRating = 4.5, RatingCount = 12
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Creamy Roman pasta with eggs, cheese, and pancetta.",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
            Steps = ["Cook spaghetti in salted boiling water.", "Fry pancetta until crispy.", "Whisk eggs with grated pecorino and pepper.", "Toss hot pasta with pancetta off heat.", "Add egg mixture quickly, tossing to coat.", "Serve immediately with extra cheese."],
            AverageRating = 4.8, RatingCount = 20
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken in a rich, spiced tomato-cream sauce.",
            Ingredients = ["Chicken thighs", "Yogurt", "Garam masala", "Tomato puree", "Heavy cream", "Onion", "Garlic", "Ginger"],
            Steps = ["Marinate chicken in yogurt and spices for 2 hours.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato puree and spices, simmer 15 minutes.", "Stir in cream and add chicken pieces.", "Simmer 10 minutes and serve with rice."],
            AverageRating = 4.7, RatingCount = 15
        },
        new()
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
            Description = "Sweet, sour, and savory Thai noodles with fresh vegetables.",
            Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Tamarind paste", "Fish sauce", "Lime", "Green onions"],
            Steps = ["Soak rice noodles in warm water 20 minutes.", "Press and cube tofu, fry until golden.", "Make sauce: tamarind, fish sauce, sugar, lime.", "Stir-fry noodles with sauce until coated.", "Add tofu and bean sprouts.", "Garnish with peanuts and green onions."],
            AverageRating = 4.3, RatingCount = 8
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef in crispy tortillas with fresh toppings.",
            Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
            Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm tortillas in a dry pan.", "Fill tortillas with seasoned beef.", "Top with lettuce, tomato, cheese.", "Serve with sour cream and salsa."],
            AverageRating = 4.2, RatingCount = 10
        },
        new()
        {
            Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts",
            Description = "Rich chocolate cakes with a molten center.",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
            Steps = ["Preheat oven to 425°F. Grease ramekins.", "Melt chocolate and butter together.", "Whisk eggs, sugar, and vanilla until thick.", "Fold chocolate mixture into eggs.", "Add flour and fold gently.", "Bake 12-14 minutes until edges are set but center jiggles."],
            AverageRating = 4.9, RatingCount = 25
        }
    ];

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().Order().ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars is < 1 or > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }
}

