arguments.new_str:
﻿@page "/"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>RecipeShare - Home</PageTitle>

<div class="text-center mb-4">
    <h1>🍳 RecipeShare</h1>
    <p class="lead">Discover and share delicious recipes from around the world.</p>
</div>

<h2>Browse by Category</h2>
<div class="row">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h4 class="card-title">@GetCategoryEmoji(category) @category</h4>
                    <p class="card-text">@RecipeService.GetByCategory(category).Count recipes</p>
                    <a href="category/@category" class="btn btn-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Asian" => "🥢",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        _ => "🍽️"
    };
}

