@page "/recipe/{Id:int}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="lead text-muted">@recipe.Category • @recipe.Description</p>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-header"><strong>Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h3>Steps</h3>
            <ol class="list-group list-group-numbered mb-3">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>

    <div class="card mt-3">
        <div class="card-body">
            <h4>Rate this Recipe</h4>
            <StarRating RecipeId="recipe.Id" />
        </div>
    </div>

    <a href="category/@recipe.Category" class="btn btn-secondary mt-3">← Back to @recipe.Category</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="d-inline-block">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= (hoverRating > 0 ? hoverRating : currentRating) ? "filled" : "")"
              @onclick="() => Rate(star)"
              @onmouseover="() => hoverRating = star"
              @onmouseout="() => hoverRating = 0"
              role="button">
            @(star <= (hoverRating > 0 ? hoverRating : currentRating) ? "★" : "☆")
        </span>
    }
    @if (submitted)
    {
        <span class="text-success ms-2">✓ Thanks for rating!</span>
    }
</div>

<style>
    .star {
        font-size: 1.8rem;
        cursor: pointer;
        color: #ccc;
        transition: color 0.15s;
    }
    .star.filled {
        color: #ffc107;
    }
    .star:hover {
        color: #ffdb4d;
    }
</style>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int currentRating;
    private int hoverRating;
    private bool submitted;

    private void Rate(int stars)
    {
        currentRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        submitted = true;
    }
}

