@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success">@successMessage</div>
}

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label class="form-label">Title</label>
        <InputText @bind-Value="model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        <ValidationMessage For="() => model.Title" />
    </div>

    <div class="mb-3">
        <label class="form-label">Category</label>
        <InputSelect @bind-Value="model.Category" class="form-select">
            <option value="">-- Select a category --</option>
            <option value="Italian">Italian</option>
            <option value="Indian">Indian</option>
            <option value="Asian">Asian</option>
            <option value="Mexican">Mexican</option>
            <option value="Desserts">Desserts</option>
            <option value="Other">Other</option>
        </InputSelect>
        <ValidationMessage For="() => model.Category" />
    </div>

    <div class="mb-3">
        <label class="form-label">Description</label>
        <InputTextArea @bind-Value="model.Description" class="form-control" rows="2" placeholder="Brief description of your recipe" />
    </div>

    <div class="mb-3">
        <label class="form-label">Ingredients (one per line)</label>
        <InputTextArea @bind-Value="model.IngredientsText" class="form-control" rows="5" placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
        <ValidationMessage For="() => model.IngredientsText" />
    </div>

    <div class="mb-3">
        <label class="form-label">Steps (one per line)</label>
        <InputTextArea @bind-Value="model.StepsText" class="form-control" rows="5" placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
        <ValidationMessage For="() => model.StepsText" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel model = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(model.Title) || string.IsNullOrWhiteSpace(model.Category))
            return;

        var recipe = new Recipe
        {
            Title = model.Title,
            Category = model.Category,
            Description = model.Description ?? string.Empty,
            Ingredients = model.IngredientsText?.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList() ?? [],
            Steps = model.StepsText?.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList() ?? []
        };

        RecipeService.AddRecipe(recipe);
        successMessage = $"'{recipe.Title}' has been submitted successfully!";
        model = new();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = string.Empty;

        public string? Description { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one ingredient")]
        public string? IngredientsText { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one step")]
        public string? StepsText { get; set; }
    }
}

